import{_ as a,o,c as r,ag as l}from"./chunks/framework.Lq6hU67C.js";const u=JSON.parse('{"title":"Troubleshooting & FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/faq.md","filePath":"troubleshooting/faq.md"}'),i={name:"troubleshooting/faq.md"};function s(t,e,n,d,h,c){return o(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="troubleshooting-faq" tabindex="-1">Troubleshooting &amp; FAQ <a class="header-anchor" href="#troubleshooting-faq" aria-label="Permalink to &quot;Troubleshooting &amp; FAQ&quot;">​</a></h1><h2 id="no-handles-appear-in-live-leaks" tabindex="-1">No handles appear in Live Leaks <a class="header-anchor" href="#no-handles-appear-in-live-leaks" aria-label="Permalink to &quot;No handles appear in Live Leaks&quot;">​</a></h2><ol><li>Confirm <strong>Recording</strong> is on (not Paused).</li><li>Re-enter Play Mode after enabling recording.</li><li>Ensure your load uses an <a href="./../reference/supported-call-sites.html">instrumented API</a>.</li><li>Check assembly is not in <a href="./../how-to/assembly-exclude-list.html">exclude list</a>.</li><li>Force recompile (touch a script) after import.</li><li>Enable <a href="./../how-to/ilpp-diagnostics.html">ILPP diagnostics</a> and check Console.</li></ol><h2 id="wrong-file-line-in-origin" tabindex="-1">Wrong file:line in origin <a class="header-anchor" href="#wrong-file-line-in-origin" aria-label="Permalink to &quot;Wrong file:line in origin&quot;">​</a></h2><ul><li>ILPP records the <strong>call site</strong> in <strong>your</strong> assembly, not internal Addressables code.</li><li>Demo manual buttons show <code>LeakDemoController.cs</code>; ILPP demo buttons show <code>AddressablesInstrumentationSamples.cs</code>.</li></ul><h2 id="handle-still-live-after-release" tabindex="-1">Handle still live after Release <a class="header-anchor" href="#handle-still-live-after-release" aria-label="Permalink to &quot;Handle still live after Release&quot;">​</a></h2><ul><li>Verify <code>Release</code> runs on the same logical load (same handle variable).</li><li><code>IsValid()</code> may still be true if another <code>AssetReference</code> holds the asset — see <a href="./../concepts/handle-identity.html">Handle identity</a>.</li></ul><h2 id="scenesurvivor-on-intentional-preload" tabindex="-1">SceneSurvivor on intentional preload <a class="header-anchor" href="#scenesurvivor-on-intentional-preload" aria-label="Permalink to &quot;SceneSurvivor on intentional preload&quot;">​</a></h2><p>Use <code>[AddressablesIntentionallyPersistent]</code> or allowlist — see <a href="./../how-to/allowlist-and-persistent-handles.html">Allowlist</a>.</p><h2 id="demo-scene-addressables-errors" tabindex="-1">Demo scene / Addressables errors <a class="header-anchor" href="#demo-scene-addressables-errors" aria-label="Permalink to &quot;Demo scene / Addressables errors&quot;">​</a></h2><ul><li>Re-run <strong>Tools → Addressables Leak Detector → Create Demo Scene</strong>.</li><li>Addressables Play Mode: <strong>Use Asset Database (fastest)</strong>.</li><li><code>demo_scene_b</code> must exist in Addressables groups; Scene B must stay <strong>disabled</strong> in Build Settings.</li></ul><h2 id="invalidprogramexception-after-import" tabindex="-1">InvalidProgramException after import <a class="header-anchor" href="#invalidprogramexception-after-import" aria-label="Permalink to &quot;InvalidProgramException after import&quot;">​</a></h2><p>Usually stale IL from a prior package version. Clean steps:</p><ol><li>Stop Play Mode</li><li>Delete <code>Library/ScriptAssemblies</code> (or full <code>Library</code> if needed)</li><li>Reimport package / recompile</li></ol><p>Report with <a href="./support.html">Support</a> template if persists.</p><h2 id="verbose-mode-overhead" tabindex="-1">Verbose mode overhead <a class="header-anchor" href="#verbose-mode-overhead" aria-label="Permalink to &quot;Verbose mode overhead&quot;">​</a></h2><p>Stack trace capture adds cost at every load/release. Disable <strong>Verbose</strong> for routine work.</p><h2 id="health-graph-snapshot-diff-missing" tabindex="-1">Health Graph / Snapshot Diff missing <a class="header-anchor" href="#health-graph-snapshot-diff-missing" aria-label="Permalink to &quot;Health Graph / Snapshot Diff missing&quot;">​</a></h2><p>MVP ships <strong>Live Leaks</strong> only. Roadmap tabs planned for 1.1 / 1.2.</p><h2 id="where-is-online-documentation" tabindex="-1">Where is online documentation? <a class="header-anchor" href="#where-is-online-documentation" aria-label="Permalink to &quot;Where is online documentation?&quot;">​</a></h2><p><a href="https://pawelca.github.io/apps/public/addressables-leak-detector/" target="_blank" rel="noreferrer">https://pawelca.github.io/apps/public/addressables-leak-detector/</a></p>',21)])])}const m=a(i,[["render",s]]);export{u as __pageData,m as default};
